import{_ as e,a as t,b as d,c as o,d as n,e as i}from"./chunks/查询额度成功.BKueuYqe.js";import{_ as r,o as p,c as s,a2 as l}from"./chunks/framework.DnrXFDHb.js";const y=JSON.parse('{"title":"Menambahkan Dropbox Channel","description":"","frontmatter":{},"headers":[],"relativePath":"id-ID/upload/dropbox.md","filePath":"id-ID/upload/dropbox.md","lastUpdated":1781962217000}'),c={name:"id-ID/upload/dropbox.md"};function h(u,a,b,m,k,g){return p(),s("div",null,[...a[0]||(a[0]=[l('<h1 id="menambahkan-dropbox-channel" tabindex="-1">Menambahkan Dropbox Channel <a class="header-anchor" href="#menambahkan-dropbox-channel" aria-label="Permalink to &quot;Menambahkan Dropbox Channel&quot;">​</a></h1><h2 id="yang-perlu-disiapkan-dahulu" tabindex="-1">Yang Perlu Disiapkan Dahulu <a class="header-anchor" href="#yang-perlu-disiapkan-dahulu" aria-label="Permalink to &quot;Yang Perlu Disiapkan Dahulu&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Requirement</th><th>Mengapa Dibutuhkan</th></tr></thead><tbody><tr><td>Dropbox account</td><td>Digunakan untuk sign in dan authorize app</td></tr><tr><td>Dropbox app</td><td>Digunakan untuk generate <code>App Key</code> dan <code>App Secret</code></td></tr><tr><td>ImgBed domain Anda</td><td>Digunakan untuk OAuth redirect URI</td></tr><tr><td>Available Dropbox storage</td><td>Digunakan sebagai lokasi file storage sebenarnya</td></tr></tbody></table><h2 id="langkah-setup" tabindex="-1">Langkah Setup <a class="header-anchor" href="#langkah-setup" aria-label="Permalink to &quot;Langkah Setup&quot;">​</a></h2><h3 id="step-1-buat-dropbox-app" tabindex="-1">Step 1: Buat Dropbox App <a class="header-anchor" href="#step-1-buat-dropbox-app" aria-label="Permalink to &quot;Step 1: Buat Dropbox App&quot;">​</a></h3><ol><li>Buka Dropbox App Console:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://www.dropbox.com/developers/apps</span></span></code></pre></div><ol start="2"><li>Buat app baru.</li><li>Untuk access type, pilih:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>App folder</span></span></code></pre></div><ol start="4"><li>Beri nama app yang mudah dikenali, misalnya <code>imgbed-app</code>.</li><li>Buka app details page setelah dibuat.</li></ol><p>Recommended access type:</p><table tabindex="0"><thead><tr><th>Access Type</th><th>Recommendation</th></tr></thead><tbody><tr><td><code>App folder</code></td><td>Recommended. Cocok dengan cara ImgBed menyimpan files.</td></tr><tr><td><code>Full Dropbox</code></td><td>Tidak recommended. ImgBed tidak membutuhkan akses seluruh account.</td></tr></tbody></table><p><img src="'+e+'" alt="Create Dropbox app" loading="lazy"></p><h3 id="step-2-tambahkan-redirect-uri" tabindex="-1">Step 2: Tambahkan Redirect URI <a class="header-anchor" href="#step-2-tambahkan-redirect-uri" aria-label="Permalink to &quot;Step 2: Tambahkan Redirect URI&quot;">​</a></h3><p>Di Dropbox app details page, cari OAuth atau Redirect URI settings dan tambahkan:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/api/oauth/dropbox/callback</span></span></code></pre></div><p>Jika memakai admin panel dari lebih dari satu domain, tambahkan setiap callback URL yang cocok.</p><p><img src="'+t+'" alt="Configure redirect URI" loading="lazy"></p><h3 id="step-3-configure-app-permissions" tabindex="-1">Step 3: Configure App Permissions <a class="header-anchor" href="#step-3-configure-app-permissions" aria-label="Permalink to &quot;Step 3: Configure App Permissions&quot;">​</a></h3><p>Buka tab <code>Permissions</code> dan enable minimal scopes ini:</p><table tabindex="0"><thead><tr><th>Scope</th><th>Required</th><th>Purpose</th></tr></thead><tbody><tr><td><code>account_info.read</code></td><td>Required</td><td>Membaca account dan quota information</td></tr><tr><td><code>files.metadata.read</code></td><td>Required</td><td>Membaca file dan folder metadata untuk path checks</td></tr><tr><td><code>files.metadata.write</code></td><td>Required</td><td>Membuat folders dan menulis metadata</td></tr><tr><td><code>files.content.write</code></td><td>Required</td><td>Upload files. Jika scope ini tidak ada, akan muncul <code>required scope &#39;files.content.write&#39;</code>.</td></tr><tr><td><code>files.content.read</code></td><td>Recommended</td><td>Mengizinkan download, preview, dan temporary file links</td></tr></tbody></table><p>Setelah memilih scopes, klik <code>Submit</code> di bagian bawah page.</p><p><img src="'+d+'" alt="Add permissions" loading="lazy"></p><p>Important:</p><table tabindex="0"><thead><tr><th>Situation</th><th>Yang Perlu Dilakukan</th></tr></thead><tbody><tr><td>Anda mengubah scopes</td><td>Jalankan token authorization flow lagi dan ambil <code>Refresh Token</code> baru.</td></tr><tr><td>Anda tidak reauthorize</td><td>Token lama tidak akan mendapat permissions baru, jadi uploads masih bisa gagal.</td></tr></tbody></table><h3 id="step-4-copy-app-credentials" tabindex="-1">Step 4: Copy App Credentials <a class="header-anchor" href="#step-4-copy-app-credentials" aria-label="Permalink to &quot;Step 4: Copy App Credentials&quot;">​</a></h3><p>Simpan dua nilai ini dari Dropbox app page:</p><table tabindex="0"><thead><tr><th>Dropbox Field</th><th>ImgBed Field</th></tr></thead><tbody><tr><td><code>App key</code></td><td><code>App Key</code></td></tr><tr><td><code>App secret</code></td><td><code>App Secret</code></td></tr></tbody></table><h3 id="step-5-isi-dropbox-channel" tabindex="-1">Step 5: Isi Dropbox Channel <a class="header-anchor" href="#step-5-isi-dropbox-channel" aria-label="Permalink to &quot;Step 5: Isi Dropbox Channel&quot;">​</a></h3><p>Di Upload Settings, pilih <code>Dropbox</code> dan isi:</p><table tabindex="0"><thead><tr><th>ImgBed Field</th><th>Yang Diisi</th></tr></thead><tbody><tr><td>Channel name</td><td>Nama yang mudah dikenali, misalnya <code>Main Dropbox</code></td></tr><tr><td>App Key</td><td>Dropbox <code>App key</code></td></tr><tr><td>App Secret</td><td>Dropbox <code>App secret</code></td></tr><tr><td>Refresh Token</td><td>Biarkan kosong dulu</td></tr><tr><td>Root directory</td><td>Optional. Default adalah <code>imgbed</code>.</td></tr><tr><td>Note</td><td>Optional</td></tr></tbody></table><p><img src="'+o+'" alt="Get token" loading="lazy"></p><h3 id="step-6-dapatkan-refresh-token" tabindex="-1">Step 6: Dapatkan Refresh Token <a class="header-anchor" href="#step-6-dapatkan-refresh-token" aria-label="Permalink to &quot;Step 6: Dapatkan Refresh Token&quot;">​</a></h3><ol><li>Di ImgBed, klik <code>Get Token</code>.</li><li>Sign in ke Dropbox account yang ingin dihubungkan.</li><li>Approve authorization prompt.</li><li>Callback page akan menampilkan <code>Refresh Token</code>.</li><li>Copy token tersebut.</li><li>Kembali ke ImgBed dan paste ke field <code>Refresh Token</code>.</li></ol><p><img src="'+n+'" alt="Copy token" loading="lazy"></p><h2 id="cara-memeriksa" tabindex="-1">Cara Memeriksa <a class="header-anchor" href="#cara-memeriksa" aria-label="Permalink to &quot;Cara Memeriksa&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Check</th><th>Expected Result</th></tr></thead><tbody><tr><td>Channel card</td><td>Dropbox channel muncul setelah save.</td></tr><tr><td>Channel switch</td><td>Channel bisa diaktifkan.</td></tr><tr><td>Token saved</td><td>Detail page menunjukkan <code>Refresh Token</code> sudah tersimpan.</td></tr><tr><td>Upload test</td><td>Test image muncul di Dropbox app folder.</td></tr></tbody></table><p>Jika quota limits aktif, klik quota query. Setelah query berhasil, channel card menampilkan used space, total space, dan last update time.</p><p><img src="'+i+`" alt="Quota query success" loading="lazy"></p><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Problem</th><th>Fix</th></tr></thead><tbody><tr><td>ImgBed mengatakan configuration incomplete</td><td>Periksa <code>App Key</code>, <code>App Secret</code>, dan <code>Refresh Token</code> semuanya sudah diisi.</td></tr><tr><td>Authorization sukses tetapi tidak ada <code>Refresh Token</code></td><td>Klik <code>Get Token</code> lagi dan pastikan offline authorization flow digunakan.</td></tr><tr><td>Upload gagal dengan <code>required scope &#39;files.content.write&#39;</code></td><td>Enable <code>files.content.write</code>, klik <code>Submit</code>, lalu ambil <code>Refresh Token</code> baru.</td></tr><tr><td>Callback gagal</td><td>Pastikan redirect URI adalah <code>https://your-domain.com/api/oauth/dropbox/callback</code>.</td></tr><tr><td>Files tidak ditemukan</td><td>Pastikan Dropbox app dibuat dalam mode <code>App folder</code>.</td></tr></tbody></table><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Buka Dropbox App Console</span></span>
<span class="line"><span>-&gt; Buat app</span></span>
<span class="line"><span>-&gt; Pilih App folder access</span></span>
<span class="line"><span>-&gt; Tambahkan https://your-domain.com/api/oauth/dropbox/callback</span></span>
<span class="line"><span>-&gt; Enable account_info.read / files.metadata.read / files.metadata.write / files.content.write</span></span>
<span class="line"><span>-&gt; Optional enable files.content.read</span></span>
<span class="line"><span>-&gt; Klik Submit</span></span>
<span class="line"><span>-&gt; Copy App Key dan App Secret</span></span>
<span class="line"><span>-&gt; Isi ke ImgBed</span></span>
<span class="line"><span>-&gt; Klik Get Token</span></span>
<span class="line"><span>-&gt; Copy Refresh Token dari callback page</span></span>
<span class="line"><span>-&gt; Paste kembali ke ImgBed dan save</span></span></code></pre></div><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ol><li>Dropbox App Console: <a href="https://www.dropbox.com/developers/apps" target="_blank" rel="noreferrer">https://www.dropbox.com/developers/apps</a></li><li>Dropbox OAuth Guide: <a href="https://developers.dropbox.com/oauth-guide" target="_blank" rel="noreferrer">https://developers.dropbox.com/oauth-guide</a></li><li>Dropbox Developer Guide: <a href="https://www.dropbox.com/developers/reference/developer-guide" target="_blank" rel="noreferrer">https://www.dropbox.com/developers/reference/developer-guide</a></li></ol>`,45)])])}const D=r(c,[["render",h]]);export{y as __pageData,D as default};
